package basic_programs;

class calss{
	int sum() {
		return 1+2;
	}
	int sub() {
		return 1*2;
	}
}

public class Class_and_object {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
        calss obj = new calss();
        System.out.println(obj.sum());
        System.out.println(obj.sub());
	}

}
